{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2f);
var edgeSoftness = GetFloat(parameters, "edgeSoftness", 0.3f);
var colorCount = Math.Clamp(GetInt(parameters, "colorCount", 3), 2, 5);
var patternType = GetChoice(parameters, "patternType", "standard");
var octaves = Math.Max(2, GetInt(parameters, "octaves", 4));
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

// Collect colors
var colorNames = new[] { "color1", "color2", "color3", "color4", "color5" };
var colors = new (float r, float g, float b)[colorCount];
var defaultColors = new[]
{
    Color.FromRgb(60, 100, 40), Color.FromRgb(120, 140, 60),
    Color.FromRgb(80, 70, 40), Color.FromRgb(40, 50, 30),
    Color.FromRgb(160, 150, 100)
};
for (var i = 0; i < colorCount; i++)
{
    var c = GetColor(parameters, colorNames[i], defaultColors[i]);
    colors[i] = (c.R / 255f, c.G / 255f, c.B / 255f);
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    float noiseVal;

    switch (patternType)
    {
        case "spot":
        {
            // Spot pattern: cellular noise with high contrast
            var cellSize = Math.Max(1, size / Math.Max(1, (int)scale));
            var cellCount = Math.Max(1, size / cellSize);
            TileableVoronoi(u * size, v * size, cellSize, cellCount, seed,
                out var nearest, out var secondNearest, out _, out _);
            noiseVal = (nearest + secondNearest) * 0.5f;
            break;
        }
        case "stripe":
        {
            // Stripes: directional tileable noise-based banding
            var dirX = u * scale * 0.5f - v * scale * 0.3f;
            var dirY = u * scale * 0.3f + v * scale * 0.5f;
            var stripeNoiseVal = TileableFractalNoise(
                dirX, dirY,
                Math.Max(1, (int)MathF.Round(scale * 0.5f)),
                3, 0.6f, 2f, seed + 100);
            // Smooth noise banding creates stripe appearance
            var band = (stripeNoiseVal * 2.5f + 0.5f) % 1f;
            noiseVal = band < 0.5f ? band * 2f : 2f - band * 2f;
            noiseVal = Math.Clamp(noiseVal, 0f, 1f);
            break;
        }
        case "fragment":
        {
            // Fragment pattern: multiple noise octaves with sharp threshold
            var frag = TileableFractalNoise(
                u * scale * 1.5f, v * scale * 1.5f,
                Math.Max(1, (int)MathF.Round(scale * 1.5f)),
                Math.Min(octaves, 4), 0.7f, 2.5f, seed + 200);
            var frag2 = TileableFractalNoise(
                u * scale * 2.5f + 30f, v * scale * 2.5f + 30f,
                Math.Max(1, (int)MathF.Round(scale * 2.5f)),
                2, 0.5f, 2f, seed + 300);
            noiseVal = frag * 0.7f + frag2 * 0.3f;
            break;
        }
        default: // standard
        {
            // Standard multi-octave fractal noise
            noiseVal = TileableFractalNoise(
                u * scale, v * scale,
                Math.Max(1, (int)MathF.Round(scale)),
                octaves, 0.55f, 2.2f, seed);
            break;
        }
    }

    // Map noise value to color band
    var bandPos = noiseVal * (colorCount - 1);
    var bandIdx = (int)MathF.Floor(bandPos);
    var bandT = bandPos - bandIdx;
    bandIdx = Math.Clamp(bandIdx, 0, colorCount - 2);

    // Edge softness: smooth the transition between bands
    if (edgeSoftness > 0f)
    {
        var remapT = MathF.Pow(bandT, 1f - edgeSoftness * 0.7f);
        bandT = remapT;
    }

    var c0 = colors[bandIdx];
    var c1 = colors[bandIdx + 1];

    float r = Lerp(c0.r, c1.r, bandT);
    float g = Lerp(c0.g, c1.g, bandT);
    float b = Lerp(c0.b, c1.b, bandT);

    // Detail noise for fabric texture
    if (patternType != "fragment")
    {
        var detail = TileableFractalNoise(
            u * scale * 8f, v * scale * 8f,
            Math.Max(1, (int)MathF.Round(scale * 8f)),
            1, 0.5f, 2f, seed + 400);
        var detailAmt = (detail - 0.5f) * 0.04f;
        r = Math.Clamp(r + detailAmt, 0f, 1f);
        g = Math.Clamp(g + detailAmt * 0.8f, 0f, 1f);
        b = Math.Clamp(b + detailAmt * 0.6f, 0f, 1f);
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
